import React, { useState } from 'react';

const CATEGORIES = ['All', 'Mechanical', 'Hardware', 'IoT', '3D Design', 'Software', 'AI'];

const featured = {
  title: 'Remote-Controlled UGV for Anthracnose Detection Using AI',
  category: ['Mechanical', 'Hardware', 'AI'],
  desc: 'A custom-fabricated ground vehicle designed for autonomous plant disease detection in agricultural fields. Integrates a Raspberry Pi-powered computer vision system with a hand-welded chassis — bridging mechanical fabrication and embedded AI in a single field-deployable unit.',
  tech: ['Raspberry Pi', 'OpenCV', 'Arduino', 'Python', 'SMAW Welding'],
  image: null,
  link: null,
};

const projects = [
  {
    title: 'Modular Semi-Autonomous UGV',
    category: ['3D Design'],
    tag: 'Concept',
    desc: 'Conceptual design of a lightweight, modular UGV based on Raspberry Pi and RTK-GPS, capable of full autonomous operation and teleoperation. Inspired by conventional tractor technology, redesigned for improved portability, lower cost, and higher field efficiency.',
    tech: ['Raspberry Pi', 'RTK-GPS', 'Fusion360', 'System Architecture'],
    image: null,
    link: null,
  },
  {
    title: 'Semi-Autonomous Mini Combine Harvester',
    category: ['3D Design'],
    tag: 'Concept',
    desc: 'Design concept for a semi-autonomous harvesting machine integrating Raspberry Pi with a paddy field detection algorithm for automated navigation. Supports both autonomous and teleoperation modes.',
    tech: ['Raspberry Pi', 'Computer Vision', 'Fusion360', 'Navigation Algorithm'],
    image: null,
    link: null,
  },
  {
    title: 'Heavy-Duty UGV Chassis Development',
    category: ['Mechanical'],
    tag: null,
    desc: 'Engineered and fabricated a heavy-duty chassis structure for unmanned ground vehicle applications. Focused on structural integrity, weight distribution, and terrain adaptability through precision welding and metal fabrication.',
    tech: ['SMAW Welding', 'MIG Welding', 'Metal Fabrication', 'Mechanical Design'],
    image: null,
    link: null,
  },
  {
    title: 'Solar Panel Tracking System',
    category: ['Mechanical', 'Hardware'],
    tag: null,
    desc: 'A dual-axis solar tracking mechanism designed to maximize photovoltaic energy output by continuously orienting panels toward the sun. Combines servo-driven mechanical structure with sensor-based control logic.',
    tech: ['Arduino', 'Servo Motor', 'LDR Sensor', 'Mechanical Design'],
    image: null,
    link: null,
  },
  {
    title: 'IoT-Based Attendance System',
    category: ['Hardware', 'IoT'],
    tag: null,
    desc: 'A real-time attendance tracking system using RFID technology and IoT connectivity. Automatically logs attendance data to a cloud database, accessible via web dashboard — eliminating manual recordkeeping.',
    tech: ['ESP32', 'RFID', 'MQTT', 'PHP', 'MySQL'],
    image: null,
    link: null,
  },
  {
    title: 'Automatic Portable Water Dispenser',
    category: ['Hardware'],
    tag: null,
    desc: 'A compact, sensor-triggered water dispensing unit designed for portable and hygienic use. Features automatic flow control via proximity sensing with a microcontroller-based actuation system.',
    tech: ['Arduino', 'Ultrasonic Sensor', 'Relay Module', '3D Printed Enclosure'],
    image: null,
    link: null,
  },
  {
    title: 'PiggyNote',
    category: ['Software'],
    tag: 'Web & Mobile',
    desc: 'A personal finance management application available on web and mobile platforms. Features expense tracking, budget categorization, and visual spending summaries — designed with a clean UI for everyday personal use.',
    tech: ['JavaScript', 'PHP', 'MySQL', 'Mobile UI'],
    image: null,
    link: null,
  },
];

function PlaceholderImage({ title }) {
  const initials = title.split(' ').slice(0, 2).map(w => w[0]).join('').toUpperCase();
  return (
    <div className="project-img-placeholder">
      <span className="project-img-initials">{initials}</span>
    </div>
  );
}

function FeaturedProject({ project }) {
  return (
    <div className="featured-card">
      <div className="featured-img-wrap">
        {project.image
          ? <img src={project.image} alt={project.title} className="featured-img" />
          : <PlaceholderImage title={project.title} />
        }
        <div className="featured-badge">⭐ Featured Project</div>
      </div>

      <div className="featured-body">
        <div className="featured-cats">
          {project.category.map(c => (
            <span key={c} className="cat-badge">{c}</span>
          ))}
        </div>
        <h3 className="featured-title">{project.title}</h3>
        <p className="featured-desc">{project.desc}</p>
        <div className="featured-tech">
          {project.tech.map(t => (
            <span key={t} className="stack-badge">{t}</span>
          ))}
        </div>
        {project.link && (
          <a href={project.link} target="_blank" rel="noreferrer" className="featured-link">
            View Project →
          </a>
        )}
      </div>
    </div>
  );
}

function ProjectCard({ project }) {
  return (
    <div className="project-card">
      <div className="project-img-wrap">
        {project.image
          ? <img src={project.image} alt={project.title} className="project-img" />
          : <PlaceholderImage title={project.title} />
        }
        {project.tag && (
          <span className="project-tag">{project.tag}</span>
        )}
      </div>
      <div className="project-body">
        <div className="project-cats">
          {project.category.map(c => (
            <span key={c} className="cat-badge cat-badge--sm">{c}</span>
          ))}
        </div>
        <div className="project-title">{project.title}</div>
        <div className="project-desc">{project.desc}</div>
        <div className="project-stack">
          {project.tech.map(t => (
            <span key={t} className="stack-badge">{t}</span>
          ))}
        </div>
        {project.link && (
          <a href={project.link} target="_blank" rel="noreferrer" className="project-link">
            View →
          </a>
        )}
      </div>
    </div>
  );
}

export default function Projects() {
  const [active, setActive] = useState('All');

  const filtered = active === 'All'
    ? projects
    : projects.filter(p => p.category.includes(active));

  return (
    <section className="section">
      <div className="section-header">
        <div className="section-num">// 03 — PROJECTS</div>
        <h2 className="section-title">Featured <span>Work</span></h2>
      </div>

      {/* Featured project */}
      <FeaturedProject project={featured} />

      {/* Filter + grid */}
      <div className="projects-section">
        <div className="projects-filter">
          {CATEGORIES.map(cat => (
            <button
              key={cat}
              className={`filter-btn${active === cat ? ' active' : ''}`}
              onClick={() => setActive(cat)}
            >
              {cat}
            </button>
          ))}
        </div>

        {filtered.length === 0 ? (
          <div className="projects-empty">No projects in this category yet.</div>
        ) : (
          <div className="projects-grid">
            {filtered.map(p => (
              <ProjectCard key={p.title} project={p} />
            ))}
          </div>
        )}
      </div>
    </section>
  );
}
